/**
 * Monta payload PATCH para /quote-life/accept.
 *
 * Lê consent_id, original_quote_request, idempotency_key e payment_transaction_id
 * diretamente dos custom_attributes da tarefa (persistidos pelos WFs 02 e 09).
 * O agente só precisa informar qual plano foi escolhido e o método de pagamento.
 */
const input = $('Gatilho').first().json;
const tarefa = $('Carregar tarefa').first().json;
const attrs = tarefa.custom_attributes ?? {};

const consentId = attrs.consent_id_cotacao;
const idempotencyKey = attrs.idempotency_key;
const paymentTransactionId = attrs.payment_transaction_id;
let originalQuoteRequest = attrs.original_quote_request;

if (!consentId) throw new Error('consent_id_cotacao ausente na tarefa. Rode a cotação antes de emitir.');
if (!originalQuoteRequest) throw new Error('original_quote_request ausente na tarefa. Rode a cotação antes de emitir.');
if (!paymentTransactionId) throw new Error('payment_transaction_id ausente na tarefa. Gere o pagamento antes de emitir.');
if (!input.plan_id && !input.operadora_codigo) {
  throw new Error('Informe plan_id ou operadora_codigo para selecionar o plano.');
}

if (typeof originalQuoteRequest === 'string') {
  try { originalQuoteRequest = JSON.parse(originalQuoteRequest); }
  catch { throw new Error('original_quote_request na tarefa não é JSON válido.'); }
}

const selectedPlan = input.plan_id
  ? { planId: input.plan_id }
  : { operadora: { codigo: input.operadora_codigo } };

const payload = {
  data: {
    consentId,
    originalQuoteRequest,
    selectedPlan,
    paymentConfirmation: {
      transactionId: paymentTransactionId,
      method: input.payment_method ?? 'pix'
    },
    acceptance: true
  }
};

return [{ json: { payload, idempotencyKey } }];

/**
 * Processa resposta e prepara dados para atualizar a tarefa.
 */
const resposta = $input.first().json;

if (resposta.errors) {
  throw new Error(`Seguradora recusou a emissão: ${JSON.stringify(resposta.errors)}`);
}
if (!resposta.data || !resposta.data.policyNumber) {
  throw new Error('Resposta inesperada na emissão: ' + JSON.stringify(resposta).slice(0, 300));
}

const d = resposta.data;
const input = $('Gatilho').first().json;

function formatBRL(v) { return v.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' }); }

// Capital de morte (cobertura principal)
const coberturaMorte = d.coberturas.find(c => c.tipo === 'morte');
const capitalMorte = coberturaMorte ? coberturaMorte.capital : 0;

// Resumo dos beneficiários (para salvar na tarefa)
const beneficiariosResumo = (d.beneficiarios || [])
  .map(b => `${b.nome} (${b.parentesco}, ${b.percentual}%)`)
  .join('; ');

const resumoCliente = `🎉 Apólice emitida!\n\n` +
  `*Nº da apólice:* ${d.policyNumber}\n` +
  `*Operadora:* ${d.selectedPlan.operadora.nome}\n` +
  `*Produto:* ${d.selectedPlan.produto.nome}\n` +
  `*Vigência:* ${d.startDate} a ${d.endDate}\n` +
  `*Capital de morte:* ${formatBRL(capitalMorte)}\n` +
  `*Mensalidade:* ${formatBRL(d.premium.mensal)}\n\n` +
  `📄 Apólice em PDF: ${d.documents.policyPdfUrl}`;

return [{
  json: {
    policyNumber: d.policyNumber,
    policyPdfUrl: d.documents.policyPdfUrl,
    resumoContratualUrl: d.documents.resumoContratualUrl,
    operadora: d.selectedPlan.operadora.nome,
    plano_nome: d.selectedPlan.produto.nome,
    startDate: d.startDate,
    endDate: d.endDate,
    premio_mensal: d.premium.mensal,
    capital_morte: capitalMorte,
    beneficiarios_resumo: beneficiariosResumo,
    fumante: d.insured?.fumante ? 'sim' : 'nao',
    resumo_cliente: resumoCliente,
    account_id: input.account_id,
    task_id: input.task_id
  }
}];
